    // We let the form submit natively to the hidden iframe to bypass CORS issues on Vercel.

    // We use a small timeout to ensure the form submission request starts 
    // before React removes the form from the DOM.
    setTimeout(() => {
        setSubmitted(true);
        localStorage.setItem('adhesure_popup_submitted', 'true');

        // Close popup after success message
